// ─────────────────────────────────────────────────────────────────────────
// STEP 1 — Normalise every raw punch record
// ─────────────────────────────────────────────────────────────────────────
const LATE_THRESHOLD_HOUR = 11; // 11:00 AM
const LATE_THRESHOLD_MINUTE = 0;

const rawRows = items.map(i => i.json);

// ─────────────────────────────────────────────────────────────────────────
// STEP 2 — Group by EmployeeID + Date
// ─────────────────────────────────────────────────────────────────────────
const groups = {};

for (const row of rawRows) {
  const empId   = String(row['Employee ID'] || '').trim();
  const name    = String(row['Name']        || '').trim();
  const rawDate = String(row['Date']        || '').trim();
  const rawTime = String(row['Time']        || '').trim();
  const status  = String(row['Punch Status'] || '').toUpperCase().trim(); // IN or OUT

  if (!empId || !rawDate || !rawTime || !status) continue;

  // Normalise date to YYYY-MM-DD
  const parsedDate = new Date(rawDate);
  const dateKey = isNaN(parsedDate)
    ? rawDate
    : parsedDate.toISOString().split('T')[0];

  // Parse time into a sortable number (minutes since midnight)
  const parseTime = (t) => {
    // Handles formats: "09:30 AM", "14:30", "9:30", "09:30:00 AM"
    const clean = t.replace(/\s+/g, ' ').trim();
    const ampmMatch = clean.match(/^(\d{1,2}):(\d{2})(?::\d{2})?\s*(AM|PM)$/i);
    const h24Match  = clean.match(/^(\d{1,2}):(\d{2})(?::\d{2})?$/);

    let h = 0, m = 0;
    if (ampmMatch) {
      h = parseInt(ampmMatch[1], 10);
      m = parseInt(ampmMatch[2], 10);
      const meridiem = ampmMatch[3].toUpperCase();
      if (meridiem === 'PM' && h !== 12) h += 12;
      if (meridiem === 'AM' && h === 12) h = 0;
    } else if (h24Match) {
      h = parseInt(h24Match[1], 10);
      m = parseInt(h24Match[2], 10);
    }
    return { totalMinutes: h * 60 + m, h, m };
  };

  const { totalMinutes, h, m } = parseTime(rawTime);
  const groupKey = `${empId}||${dateKey}`;

  if (!groups[groupKey]) {
    groups[groupKey] = {
      employeeId: empId,
      name,
      date: dateKey,
      inPunches:  [],
      outPunches: []
    };
  }

  if (status === 'IN')  groups[groupKey].inPunches.push({ rawTime, totalMinutes, h, m });
  if (status === 'OUT') groups[groupKey].outPunches.push({ rawTime, totalMinutes, h, m });
}

// ─────────────────────────────────────────────────────────────────────────
// STEP 3 — For each group, derive Check-In / Check-Out / Late Flag
// ─────────────────────────────────────────────────────────────────────────
const results = [];

for (const key of Object.keys(groups)) {
  const g = groups[key];

  // Sort punches
  g.inPunches.sort((a, b)  => a.totalMinutes - b.totalMinutes);
  g.outPunches.sort((a, b) => a.totalMinutes - b.totalMinutes);

  const firstIn  = g.inPunches[0]  || null;
  const lastOut  = g.outPunches[g.outPunches.length - 1] || null;

  // Format time helper → "HH:MM AM/PM"
  const formatTime = (punch) => {
    if (!punch) return null;
    let h = punch.h, m = punch.m;
    const meridiem = h >= 12 ? 'PM' : 'AM';
    const displayH = h % 12 === 0 ? 12 : h % 12;
    return `${String(displayH).padStart(2,'0')}:${String(m).padStart(2,'0')} ${meridiem}`;
  };

  // Late Rule: first IN punch after 11:00 AM
  let lateFlag = 'NO';
  let missingOut = false;

  if (firstIn) {
    const lateThreshold = LATE_THRESHOLD_HOUR * 60 + LATE_THRESHOLD_MINUTE;
    if (firstIn.totalMinutes > lateThreshold) lateFlag = 'YES';
  }

  // Edge-case: missing OUT punch
  if (!lastOut) {
    missingOut = true;
  }

  results.push({
    json: {
      employeeId:  g.employeeId,
      name:        g.name,
      date:        g.date,
      checkIn:     formatTime(firstIn)  || 'MISSING',
      checkOut:    formatTime(lastOut)  || 'MISSING',
      lateFlag,
      missingOut,
      rawInCount:  g.inPunches.length,
      rawOutCount: g.outPunches.length
    }
  });
}

return results;

// Merge the late employee data (from filter node) with the existing
// monthly counter data (from Google Sheets read). 
// $input.item.json = the late attendance record
// $('Read Monthly Late Counter').item.json = existing counter row (or empty)

const attendance = $input.item.json;
const existingRow = $('Read Monthly Late Counter').item.json;

const monthYear = new Date(attendance.date)
  .toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

// If no existing row was found, existingRow will have no Employee ID
const previousCount = parseInt(existingRow['Current Monthly Late Count'] || '0', 10);
const newCount = previousCount + 1;

// Cap at 3 for routing purposes (3+ all get 3rd-strike treatment)
const strikeLevel = Math.min(newCount, 3);

return {
  json: {
    ...attendance,
    previousCount,
    newCount,
    strikeLevel,
    monthYear,
    lastWarningDate: attendance.date,
    isNewRow: !existingRow['Employee ID']
  }
};

parameters.text:
=You are a senior HR communication specialist at Growify.

Draft a formal and serious final-strike warning email for the following employee:

Employee Name: {{ $json.name }}
Employee ID: {{ $json.employeeId }}
Date of Late Arrival: {{ $json.date }}
Check-In Time: {{ $json.checkIn }}
Total Late Arrivals This Month: {{ $json.newCount }}
Mandatory Meeting: Today at 5:00 PM
Calendar Link: {{ $json.calendarEventLink || 'See attached calendar invite' }}

Guidelines:
- Tone: Formal, serious, and unambiguous. This is the THIRD and final strike.
- Clearly state this is the third late arrival this month — a threshold that triggers formal HR review.
- Inform the employee of the mandatory 5:00 PM meeting TODAY with HR.
- Include the calendar event link prominently.
- State that failure to attend the meeting without prior notice will be treated as non-compliance.
- Maintain professional dignity — do not shame or threaten.
- Length: 4–5 paragraphs.

Output ONLY the email body. Start with 'Dear {{ $json.name }},'.

additionalFields.description:
={{ `Mandatory HR review meeting for ${$json.name} (${$json.employeeId}) following their third late arrival this month.

Date of Incident: ${$json.date}
Check-In Time: ${$json.checkIn}

This meeting is required. Please contact HR immediately if you have an emergency.` }}
